$\begin{align}
\displaystyle\sum_{n=1}^4 \dfrac{k}{n+1}&= \dfrac{k}{(1)+1} + \dfrac{k}{(2)+1} + \dfrac{k}{(3)+1} + \dfrac{k}{(4)+1}
\\\\
&= \dfrac{k}{2} + \dfrac{k}{3} + \dfrac{k}{4} + \dfrac{k}{5}
\end{align}$

$\begin{align}
\displaystyle\sum_{k=0}^3 \dfrac{6k}{j-2}&= \dfrac{6(0)}{j-2} + \dfrac{6(1)}{j-2} + \dfrac{6(2)}{j-2} + \dfrac{6(3)}{j-2}
\\\\
&= 0 +  \dfrac{6}{j-2} +  \dfrac{12}{j-2} +  \dfrac{18}{j-2}
\end{align}$

$\begin{align}
\displaystyle\sum_{i=1}^4 \dfrac{7i}{4n-9}&= \dfrac{7(1)}{4n-9} + \dfrac{7(2)}{4n-9} + \dfrac{7(3)}{4n-9} +\dfrac{7(4)}{4n-9}
\\\\
&= \dfrac{7}{4n-9} + \dfrac{14}{4n-9} + \dfrac{21}{4n-9} + \dfrac{28}{4n-9}
\end{align}$
